1	import { describe, it, expect, beforeAll } from "vitest";
2	import {
3	  getOutcomeColor,
4	  scaleNumber,
5	  buildLinePath,
6	  formatTimestampLabel,
7	  formatBucketRangeLabel,
8	  formatSignedCurrency,
9	} from "@/features/analytics/chartUtils";
10	
11	beforeAll(() => {
12	  process.env.TZ = "UTC";
13	});
14	
15	describe("getOutcomeColor", () => {
16	  it("returns first color for index 0", () => expect(getOutcomeColor(0)).toBe("#818cf8"));
17	  it("returns second color for index 1", () => expect(getOutcomeColor(1)).toBe("#22c55e"));
18	  it("wraps around after 6 colors", () => expect(getOutcomeColor(6)).toBe("#818cf8"));
19	  it("wraps correctly for index 7", () => expect(getOutcomeColor(7)).toBe("#22c55e"));
20	  it("returns fallback for NaN index", () => expect(getOutcomeColor(NaN)).toBe("#818cf8"));
21	  it("returns fallback for negative index", () => expect(getOutcomeColor(-1)).toBe("#818cf8"));
22	});
23	
24	describe("scaleNumber", () => {
25	  it("maps domain midpoint to range midpoint", () => {
26	    expect(scaleNumber(50, 0, 100, 0, 200)).toBe(100);
27	  });
28	  it("maps domain min to range min", () => {
29	    expect(scaleNumber(0, 0, 100, 10, 20)).toBe(10);
30	  });
31	  it("maps domain max to range max", () => {
32	    expect(scaleNumber(100, 0, 100, 10, 20)).toBe(20);
33	  });
34	  it("returns range midpoint when domain is zero-width", () => {
35	    expect(scaleNumber(5, 5, 5, 0, 100)).toBe(50);
36	  });
37	  it("handles inverted range", () => {
38	    expect(scaleNumber(0, 0, 100, 200, 0)).toBe(200);
39	  });
40	  it("extrapolates beyond domain", () => {
41	    expect(scaleNumber(200, 0, 100, 0, 100)).toBe(200);
42	  });
43	});
44	
45	describe("buildLinePath", () => {
46	  it("returns empty string for empty array", () => {
47	    expect(buildLinePath([])).toBe("");
48	  });
49	  it("returns M command for single point", () => {
50	    expect(buildLinePath([{ x: 10, y: 20 }])).toBe("M 10.00 20.00");
51	  });
52	  it("builds M then L commands for multiple points", () => {
53	    expect(
54	      buildLinePath([
55	        { x: 0, y: 0 },
56	        { x: 50, y: 100 },
57	        { x: 100, y: 50 },
58	      ]),
59	    ).toBe("M 0.00 0.00 L 50.00 100.00 L 100.00 50.00");
60	  });
61	  it("formats decimals to two places", () => {
62	    expect(buildLinePath([{ x: 1.1234, y: 2.5678 }])).toBe("M 1.12 2.57");
63	  });
64	});
65	
66	describe("formatTimestampLabel", () => {
67	  it("formats day interval as short date", () => {
68	    const result = formatTimestampLabel("2024-06-15T00:00:00Z", "day");
69	    expect(result).toMatch(/15/);
70	    expect(result).not.toMatch(/:/);
71	  });
72	  it("formats hour interval with date and time", () => {
73	    const result = formatTimestampLabel("2024-06-15T14:30:00Z", "hour");
74	    expect(result).toMatch(/15/);
75	    expect(result).toMatch(/(:30|30)/);
76	  });
77	  it("hour result is longer than day result for same timestamp", () => {
78	    const dayLabel = formatTimestampLabel("2024-06-15T14:30:00Z", "day");
79	    const hourLabel = formatTimestampLabel("2024-06-15T14:30:00Z", "hour");
80	    expect(hourLabel.length).toBeGreaterThan(dayLabel.length);
81	  });
82	});
83	
84	describe("formatBucketRangeLabel", () => {
85	  it("returns date label for day interval (delegates to formatTimestampLabel)", () => {
86	    const bucket = formatBucketRangeLabel("2024-06-15T00:00:00Z", "2024-06-16T00:00:00Z", "day");
87	    const direct = formatTimestampLabel("2024-06-15T00:00:00Z", "day");
88	    expect(bucket).toBe(direct);
89	  });
90	  it("returns time range with separator for hour interval", () => {
91	    const result = formatBucketRangeLabel("2024-06-15T14:00:00Z", "2024-06-15T15:00:00Z", "hour");
92	    expect(result).toMatch(/ - /);
93	    expect(result).toMatch(/:00/);
94	  });
95	});
96	
97	describe("formatSignedCurrency", () => {
98	  it("prepends + for positive values", () => expect(formatSignedCurrency(42.5)).toBe("+42.50"));
99	  it("prepends nothing extra for negative values", () => expect(formatSignedCurrency(-10)).toBe("-10.00"));
100	  it("no prefix for zero", () => expect(formatSignedCurrency(0)).toBe("0.00"));
101	  it("formats large positive with K suffix", () => expect(formatSignedCurrency(5000)).toBe("+5.0K"));
102	  it("formats large negative with K suffix", () => expect(formatSignedCurrency(-5000)).toBe("-5.0K"));
103	});
